import React, { useState } from 'react';
import { ChevronLeft, ChevronRight, Star } from 'lucide-react';

const testimonials = [
  {
    id: 1,
    quote: "SynapseFlow has revolutionized how we manage projects. The intuitive interface and powerful features have saved us countless hours and improved our team's collaboration significantly.",
    name: "Alice Johnson",
    title: "Project Manager",
    company: "Tech Innovations Inc.",
    rating: 5,
  },
  {
    id: 2,
    quote: "As a growing startup, we needed a solution that could scale with us. SynapseFlow provided exactly that, with excellent support and a clear roadmap for the future. Highly recommended!",
    name: "Bob Williams",
    title: "CEO",
    company: "Creative Solutions Co.",
    rating: 5,
  },
  {
    id: 3,
    quote: "I was skeptical at first, but SynapseFlow exceeded all my expectations. The automation capabilities are a game-changer, and the analytics provide insights I never thought possible.",
    name: "Charlie Brown",
    title: "Operations Lead",
    company: "Global Enterprises",
    rating: 4,
  },
];

const TestimonialCarousel = () => {
  const [currentSlide, setCurrentSlide] = useState(0);

  const nextSlide = () => {
    setCurrentSlide((prev) => (prev + 1) % testimonials.length);
  };

  const prevSlide = () => {
    setCurrentSlide((prev) => (prev - 1 + testimonials.length) % testimonials.length);
  };

  const renderStars = (rating) => {
    const stars = [];
    for (let i = 0; i < 5; i++) {
      stars.push(
        <Star
          key={i}
          className={`w-5 h-5 ${i < rating ? 'fill-zinc-400 text-zinc-400' : 'text-zinc-700'}`}
        />
      );
    }
    return stars;
  };

  return (
    <section className="relative w-full py-16 px-4 sm:px-6 lg:px-8 bg-zinc-900 text-zinc-300 font-sans">
      <div className="max-w-5xl mx-auto">
        <h2 className="text-3xl sm:text-4xl font-bold text-center mb-12 text-zinc-100">
          What Our Clients Say
        </h2>
        <div className="relative">
          <div className="flex flex-col items-center text-center p-8 rounded-md bg-zinc-800/50 border border-zinc-700 shadow-lg">
            <p className="text-lg sm:text-xl italic mb-6 leading-relaxed max-w-2xl">
              "{testimonials[currentSlide].quote}"
            </p>
            <div className="flex items-center mb-3">
              {renderStars(testimonials[currentSlide].rating)}
            </div>
            <p className="font-semibold text-zinc-200">{testimonials[currentSlide].name}</p>
            <p className="text-sm text-zinc-400">{testimonials[currentSlide].title}, {testimonials[currentSlide].company}</p>
          </div>

          <button
            onClick={prevSlide}
            className="absolute left-0 top-1/2 -translate-y-1/2 transform bg-zinc-700 hover:bg-zinc-600 text-zinc-300 p-3 rounded-full focus:outline-none focus:ring-2 focus:ring-zinc-500 focus:ring-opacity-50 transition duration-300"
            aria-label="Previous testimonial"
          >
            <ChevronLeft className="w-6 h-6" />
          </button>
          <button
            onClick={nextSlide}
            className="absolute right-0 top-1/2 -translate-y-1/2 transform bg-zinc-700 hover:bg-zinc-600 text-zinc-300 p-3 rounded-full focus:outline-none focus:ring-2 focus:ring-zinc-500 focus:ring-opacity-50 transition duration-300"
            aria-label="Next testimonial"
          >
            <ChevronRight className="w-6 h-6" />
          </button>
        </div>
        <div className="flex justify-center mt-8 space-x-3">
          {testimonials.map((_, index) => (
            <button
              key={index}
              className={`w-3 h-3 rounded-full ${currentSlide === index ? 'bg-zinc-400' : 'bg-zinc-600'} transition duration-300 focus:outline-none focus:ring-2 focus:ring-zinc-500`}
              onClick={() => setCurrentSlide(index)}
              aria-label={`Go to testimonial ${index + 1}`}
            ></button>
          ))}
        </div>
      </div>
    </section>
  );
};

export default TestimonialCarousel;

